#!/usr/bin/env node
/**
 * Course Progress Enrichment Script
 *
 * Matches Wix course participant names to D1 users and generates
 * UPDATE SQL for enrollment records (completed_at, certificate_issued_at).
 *
 * Usage:
 *   node scripts/enrich-progress.mjs > scripts/enrich-progress.sql
 *
 * Requires /tmp/user-maps.json (generated by querying D1 users).
 */

import { readFileSync } from 'fs';
import { homedir } from 'os';
import { join } from 'path';

// ── Manual overrides: participant name → email ──
const MANUAL_OVERRIDES = {
  'MM': 'maggievdb@gmail.com',
  'Maggie McCarthy': 'maggievdb@gmail.com',
  'mollyg242': 'mollyg242@gmail.com',
  'Molly Y': 'mollyg242@gmail.com',
  'Amelia D': 'maroonnurse@gmail.com',
  'Amelia Burke': 'maroonnurse@gmail.com',
  'Kendal Fraser - Reproductive Health Education': 'kendalfertility@gmail.com',
  'Pam Schoenfeld': 'womenfamilynutrition@gmail.com',
  'Naomi Whittaker': 'naomimwhittaker@gmail.com',
  'Brian Whittaker': 'brianrwhittaker@gmail.com',
  'RRM Academy Administrator': null, // skip
  'Gianna': null, // skip - not a real student
};

// ── Ignore list ──
const IGNORE_NAMES = new Set(['daniell132', 'Danie']);

// ── Course participant files ──
const COURSES = [
  {
    file: join(homedir(), 'Downloads', 'course participants - masterclass.csv'),
    courseId: 'masterclass-endo-surgery',
  },
  {
    file: join(homedir(), 'Downloads', 'course participants - long term endo.csv'),
    courseId: 'long-term-endo-management',
  },
];

// ── Load user maps ──
const { nameMap, prefixMap } = JSON.parse(readFileSync('/tmp/user-maps.json', 'utf8'));

// ── Parse the weird Wix CSV format (entire row is quoted) ──
function parseParticipantCSV(text) {
  const lines = text.trim().split('\n');
  // Header line: "#,Name,Status,Performance %,Performance,Last Activity,Date Joined,Pricing,Certificate"
  const rows = [];
  for (let i = 1; i < lines.length; i++) {
    let line = lines[i].trim();
    // Strip outer quotes
    if (line.startsWith('"') && line.endsWith('"')) {
      line = line.slice(1, -1);
    }
    const parts = line.split(',');
    // parts: [#, Name, Status, Performance %, Performance, Last Activity, Date Joined, Pricing, Certificate]
    // But name could contain commas (unlikely here). Rejoin if we have too many parts.
    if (parts.length > 9) {
      // Name has a comma — rejoin extra parts into name
      const extra = parts.length - 9;
      const name = parts.slice(1, 2 + extra).join(',');
      parts.splice(1, 1 + extra, name);
    }
    rows.push({
      name: parts[1]?.trim(),
      status: parts[2]?.trim(),
      performancePct: parts[3]?.replace('%', '').trim(),
      lastActivity: parts[5]?.trim(),
      certificate: parts[8]?.trim(),
    });
  }
  return rows;
}

// ── Match a participant name to an email ──
function matchName(name) {
  if (!name) return null;
  if (IGNORE_NAMES.has(name)) return null;

  // 1. Manual override
  if (name in MANUAL_OVERRIDES) return MANUAL_OVERRIDES[name];

  // 2. Full name match (case-insensitive)
  const lower = name.toLowerCase().trim();
  if (nameMap[lower]) return nameMap[lower];

  // 3. Email prefix match
  if (prefixMap[lower]) return prefixMap[lower];

  // 4. Try with dots replaced by nothing
  const noDots = lower.replace(/\./g, '');
  if (prefixMap[noDots]) return prefixMap[noDots];

  return undefined; // unmatched
}

// ── Parse Wix date format: "Oct 30 2025" → "2025-10-30" ──
function parseWixDate(dateStr) {
  if (!dateStr || dateStr === 'Not issued') return null;
  // Remove "Issued " prefix
  dateStr = dateStr.replace(/^Issued\s+/, '');
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return null;
  return d.toISOString().slice(0, 10);
}

function sqlEscape(s) {
  return s.replace(/'/g, "''");
}

// ── Main ──
const updates = [];
const unmatched = [];
const skipped = [];

for (const { file, courseId } of COURSES) {
  const text = readFileSync(file, 'utf8');
  const participants = parseParticipantCSV(text);

  for (const p of participants) {
    const email = matchName(p.name);

    if (email === null) {
      skipped.push({ name: p.name, course: courseId });
      continue;
    }

    if (email === undefined) {
      unmatched.push({ name: p.name, course: courseId });
      continue;
    }

    // Only generate UPDATE for participants who have finished or have certificates
    const certificateDate = parseWixDate(p.certificate);
    const isFinished = p.status === 'Finished';

    if (isFinished || certificateDate) {
      // For Finished without certificate, use last activity date as completion date
      const completedAt = isFinished
        ? (certificateDate || parseWixDate(p.lastActivity))
        : null;
      updates.push({
        email,
        courseId,
        name: p.name,
        completedAt,
        certificateDate,
        status: p.status,
        performancePct: p.performancePct,
      });
    }
  }
}

// ── Generate SQL ──
process.stdout.write('-- Course progress enrichment — generated ' + new Date().toISOString() + '\n');
process.stdout.write('-- Updates enrollment records with completed_at and certificate_issued_at\n\n');

for (const u of updates) {
  const sets = [];
  if (u.completedAt) sets.push(`completed_at = '${u.completedAt}'`);
  if (u.certificateDate) sets.push(`certificate_issued_at = '${u.certificateDate}'`);

  if (sets.length === 0) continue;

  process.stdout.write(`-- ${u.name} (${u.status}, ${u.performancePct}%)\n`);
  process.stdout.write(
    `UPDATE enrollment SET ${sets.join(', ')} ` +
    `WHERE user_id = (SELECT id FROM user WHERE email = '${sqlEscape(u.email)}') ` +
    `AND course_id = '${sqlEscape(u.courseId)}';\n\n`
  );
}

// ── Summary ──
process.stderr.write('\n=== Course Progress Enrichment Summary ===\n');
process.stderr.write(`Updates generated:    ${updates.length}\n`);
process.stderr.write(`Skipped (manual):     ${skipped.length}\n`);
process.stderr.write(`Unmatched:            ${unmatched.length}\n`);
if (unmatched.length > 0) {
  process.stderr.write('\nUnmatched participants:\n');
  for (const u of unmatched) {
    process.stderr.write(`  - ${u.name} (${u.course})\n`);
  }
}
process.stderr.write('==========================================\n');
